import{_ as o,o as d,c as s,ag as r,j as t,ah as a}from"./chunks/framework.D9bIGSBm.js";const b=JSON.parse('{"title":"依赖管理","description":"","frontmatter":{},"headers":[],"relativePath":"settings/dependencies.md","filePath":"settings/dependencies.md"}'),n={name:"settings/dependencies.md"};function l(i,e,h,c,p,u){return d(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="依赖管理" tabindex="-1">依赖管理 <a class="header-anchor" href="#依赖管理" aria-label="Permalink to &quot;依赖管理&quot;">​</a></h1><p><strong>入口：</strong> 侧边栏 → <strong>设置</strong> → <strong>依赖管理</strong></p><p>依赖管理页面用于检测与安装应用所需的外部工具（CLI 及运行时）。相比 <a href="/docs/guide/prerequisites.html">环境准备</a> 中的首次安装引导，本页提供更完整的依赖状态查看与安装来源配置。</p><hr><h2 id="依赖分组" tabindex="-1">依赖分组 <a class="header-anchor" href="#依赖分组" aria-label="Permalink to &quot;依赖分组&quot;">​</a></h2><p>依赖按重要性分组显示：</p><table tabindex="0"><thead><tr><th>分组</th><th>说明</th></tr></thead><tbody><tr><td><strong>AI CLI · 至少安装一个</strong></td><td>四个 AI CLI 家族 <strong>Claude / Codex / OpenCode / Kimi</strong> 归为一组（v0.10.0 起 Kimi 纳入），任务至少需要其中一个才能运行；全部未安装时，分组顶部显示醒目提示「请至少安装一个:Claude / Codex / OpenCode / Kimi」</td></tr><tr><td><strong>必须依赖</strong></td><td>其他核心工具，如 git</td></tr><tr><td><strong>可选依赖</strong></td><td>扩展功能所需，缺少时部分功能受限</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">四个 AI CLI 都是可选其一</p><p>你不必装齐四个 CLI——按需选用即可。例如只用 Claude、或只用 OpenCode 配合第三方供应商，都能正常发起任务。只要四者中已安装任意一个，分组警告即消失。</p></div><hr><h2 id="依赖状态检测" tabindex="-1">依赖状态检测 <a class="header-anchor" href="#依赖状态检测" aria-label="Permalink to &quot;依赖状态检测&quot;">​</a></h2><p><img src="'+a+'" alt="依赖管理页面，列出 Claude CLI、Codex CLI、OpenCode CLI、git 等依赖项，每项显示来源标签与版本号，未安装项右侧提供安装按钮"></p><p>页面加载时自动扫描系统环境，每个依赖项显示以下信息：</p><ul><li><strong>状态：</strong> 已安装的依赖显示绿色<strong>已安装</strong>标签；未安装则显示安装入口</li><li><strong>来源标签：</strong> 应用安装 / 系统安装 / 未安装</li><li><strong>版本号：</strong> 已安装时显示检测到的具体版本</li><li><strong>操作按钮（仅未安装时显示）：</strong> 支持应用内安装的依赖显示<strong>安装</strong>按钮（点击后变为<strong>安装中…</strong>）；不支持应用内安装的依赖显示<strong>触发系统安装</strong>按钮——点击后调起操作系统自带的安装流程（目前对应 macOS 上的 git：弹出系统的命令行开发者工具安装对话框），完成后回到本页重新检测即可</li></ul><hr><h2 id="安装依赖" tabindex="-1">安装依赖 <a class="header-anchor" href="#安装依赖" aria-label="Permalink to &quot;安装依赖&quot;">​</a></h2><p>点击依赖项右侧的<strong>安装</strong>按钮后，进度日志会实时展示在下方：</p>',16),t("table",{tabindex:"0"},[t("thead",null,[t("tr",null,[t("th",null,"日志阶段"),t("th",null,"含义")])]),t("tbody",null,[t("tr",null,[t("td",null,"下载中 xx%"),t("td",null,"正在从指定来源下载安装包")]),t("tr",null,[t("td",null,"解压中…"),t("td",null,"正在解压下载的文件")]),t("tr",null,[t("td",null,"执行中…"),t("td",null,"正在运行安装脚本")]),t("tr",null,[t("td",{错误信息:""},"失败："),t("td",null,"安装失败，错误详情保留在日志区域")])])],-1),r('<p>安装日志在关闭对话框后仍然保留，导航到其他页面再返回依然可以查看。</p><div class="tip custom-block"><p class="custom-block-title">安装完成后需重启应用</p><p>新安装的工具需要重启应用才能被正确检测到，因为 <code>PATH</code> 环境变量在应用启动时已固定。请根据提示重启。</p></div><p>安装失败时，日志区域提供<strong>重试</strong>按钮。若反复失败，请参阅 <a href="/docs/reference/troubleshooting.html">故障排查</a> 查看常见原因与解决方法。</p><hr><h2 id="安装来源配置" tabindex="-1">安装来源配置 <a class="header-anchor" href="#安装来源配置" aria-label="Permalink to &quot;安装来源配置&quot;">​</a></h2><p><strong>入口：</strong> 依赖管理页面 → <strong>安装来源</strong> 区域</p><p>安装来源决定应用从哪里下载 CLI 工具。提供三种模式：</p><table tabindex="0"><thead><tr><th>来源</th><th>说明</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>官方脚本</strong></td><td>使用各 CLI 官方提供的安装脚本</td><td>网络直连、访问官方源无障碍时</td></tr><tr><td><strong>GitHub 直连</strong></td><td>直接从 GitHub Releases 下载</td><td>网络可访问 GitHub 时</td></tr><tr><td><strong>GitHub 加速</strong></td><td>通过镜像服务转发 GitHub Releases</td><td>国内网络访问 GitHub 受限时（推荐）</td></tr></tbody></table><p>选择 <strong>GitHub 加速</strong> 时，还可在下方出现的输入框中填写<strong>自定义镜像前缀</strong>（v0.6.5 起支持），格式为 <code>https://your-mirror.example.com/</code>，留空则使用内置默认镜像。</p><div class="tip custom-block"><p class="custom-block-title">国内网络建议</p><p>若你在中国大陆使用，GitHub 直连可能速度较慢或不稳定，建议选择 <strong>GitHub 加速</strong> 并使用内置默认镜像或自填可信镜像地址。</p></div><div class="tip custom-block"><p class="custom-block-title">OpenCode CLI 的安装方式</p><p><strong>OpenCode CLI</strong>（v0.9.0 起可在本页一键安装）在 Windows 上由应用自管从 GitHub 下载并解压安装（同样支持上述 GitHub 直连 / 加速来源）；在 macOS / Linux 上则调用官方安装脚本（<code>opencode.ai/install</code>）。安装完成后同样需按提示重启应用。</p></div><div class="tip custom-block"><p class="custom-block-title">Kimi Code CLI 仅检测、暂不支持一键安装</p><p><strong>Kimi Code CLI</strong>（v0.10.0 起纳入检测）卡片会自动检测安装状态与版本（<code>kimi --version</code>），但暂不支持应用内一键安装——未安装时卡片会提示前往官网按官方说明安装，装好后回到本页重新检测（或按提示重启应用）即可。</p></div><hr><h2 id="下载代理配置" tabindex="-1">下载代理配置 <a class="header-anchor" href="#下载代理配置" aria-label="Permalink to &quot;下载代理配置&quot;">​</a></h2><p>安装依赖时的下载请求支持独立于模型供应商的代理设置，同样是三态：</p><table tabindex="0"><thead><tr><th>模式</th><th>说明</th></tr></thead><tbody><tr><td><strong>跟随系统</strong></td><td>实时读取操作系统当前的代理设置（如 Clash 等代理工具接管系统代理后即可生效），默认模式</td></tr><tr><td><strong>自定义</strong></td><td>单独为依赖下载指定代理地址</td></tr><tr><td><strong>直连</strong></td><td>不使用任何代理，直接连接目标地址</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>下载代理与 <a href="/docs/settings/providers.html#网络代理">模型供应商 → 网络代理</a> 是两套独立的三态开关，互不影响——前者只管 CLI 安装包下载，后者管的是任务运行时 CLI 对该供应商发出的请求。</p></div><hr><h2 id="与环境准备页的分工" tabindex="-1">与环境准备页的分工 <a class="header-anchor" href="#与环境准备页的分工" aria-label="Permalink to &quot;与环境准备页的分工&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>位置</th></tr></thead><tbody><tr><td>首次安装的快速上手路径</td><td><a href="/docs/guide/prerequisites.html">环境准备</a></td></tr><tr><td>安装来源配置与自定义镜像</td><td>本页（依赖管理）</td></tr><tr><td>安装失败的排查方法</td><td><a href="/docs/reference/troubleshooting.html">故障排查</a></td></tr></tbody></table><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/settings/mcp.html">MCP 服务器</a> — 为模型配置外部工具服务</li><li><a href="/docs/reference/troubleshooting.html">故障排查</a> — CLI 安装失败时的诊断与修复</li></ul>',23)])])}const m=o(n,[["render",l]]);export{b as __pageData,m as default};
